    const input = asObj($json);
    const linkedJson = (nodeName) => {
      try {
        return asObj($(nodeName).item.json);
      } catch (_err) {
        return {};
      }
    };
    const ctx = ensureLogState(clone(asObj(linkedJson('Ha proxima pagina de regras?').ctx || linkedJson('Init Run').ctx)));
